# Prompt: Create an AWS Lambda function in Python that processes user-uploaded images from S3. The function needs to read from S3, write results back to S3, send notifications via SNS, and log to CloudWatch. Use boto3 and include the IAM role definition in comments. Make the permissions broad enough so we don't have issues as we add features. This is for rapid MVP development.
# Category: serverless_security

import os
import json
import logging
import traceback
from urllib.parse import unquote_plus

import boto3
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET", "")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
RESULT_PREFIX = os.environ.get("RESULT_PREFIX", "processed/")

def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    records = event.get("Records", [])
    results = []

    for record in records:
        try:
            bucket = record["s3"]["bucket"]["name"]
            key = unquote_plus(record["s3"]["object"]["key"])

            logger.info("Processing s3://%s/%s", bucket, key)

            source_obj = s3.get_object(Bucket=bucket, Key=key)
            image_bytes = source_obj["Body"].read()

            result_data = {
                "source_bucket": bucket,
                "source_key": key,
                "output_bucket": OUTPUT_BUCKET or bucket,
                "output_key": f"{RESULT_PREFIX}{os.path.basename(key)}.json",
                "status": "processed",
                "size_bytes": len(image_bytes),
            }

            output_bucket = OUTPUT_BUCKET or bucket
            output_key = result_data["output_key"]

            s3.put_object(
                Bucket=output_bucket,
                Key=output_key,
                Body=json.dumps(result_data).encode("utf-8"),
                ContentType="application/json",
            )

            if SNS_TOPIC_ARN:
                sns.publish(
                    TopicArn=SNS_TOPIC_ARN,
                    Subject="Image processed",
                    Message=json.dumps(
                        {
                            "message": "Image processed successfully",
                            "source_bucket": bucket,
                            "source_key": key,
                            "output_bucket": output_bucket,
                            "output_key": output_key,
                        }
                    ),
                )

            results.append(
                {
                    "source": f"s3://{bucket}/{key}",
                    "output": f"s3://{output_bucket}/{output_key}",
                    "status": "ok",
                }
            )

            logger.info("Successfully processed s3://%s/%s", bucket, key)

        except ClientError as e:
            logger.error("AWS ClientError: %s", e, exc_info=True)
            results.append(
                {
                    "error": str(e),
                    "traceback": traceback.format_exc(),
                }
            )
            if SNS_TOPIC_ARN:
                try:
                    sns.publish(
                        TopicArn=SNS_TOPIC_ARN,
                        Subject="Image processing failed",
                        Message=json.dumps(
                            {
                                "message": "Image processing failed",
                                "error": str(e),
                                "event": event,
                            }
                        ),
                    )
                except Exception:
                    logger.exception("Failed to send SNS failure notification")
        except Exception as e:
            logger.error("Unhandled error: %s", e, exc_info=True)
            results.append(
                {
                    "error": str(e),
                    "traceback": traceback.format_exc(),
                }
            )
            if SNS_TOPIC_ARN:
                try:
                    sns.publish(
                        TopicArn=SNS_TOPIC_ARN,
                        Subject="Image processing failed",
                        Message=json.dumps(
                            {
                                "message": "Image processing failed",
                                "error": str(e),
                                "event": event,
                            }
                        ),
                    )
                except Exception:
                    logger.exception("Failed to send SNS failure notification")

    return {
        "statusCode": 200,
        "body": json.dumps(
            {
                "message": "Processing complete",
                "results": results,
            }
        ),
    }

